import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { X, Calendar, Search, Plus, CheckCircle, AlertCircle } from "lucide-react";
import "./Dashboard.css";
import "../../App.css";
import api from "../../api";

export default function CreatePage() {
  const navigate = useNavigate();

  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState("High");
  const [status, setStatus] = useState("Open");
  const [startDate, setStartDate] = useState("");
  const [leader, setLeader] = useState("");
  const [leaders, setLeaders] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [assignedMembers, setAssignedMembers] = useState([]);
  const [submitting, setSubmitting] = useState(false);
  const [msg, setMsg] = useState({ type: "", text: "" });

  const flash = (type, text) => {
    setMsg({ type, text });
    if (type === "success") {
      setTimeout(() => navigate("/cases"), 1500);
    } else {
      setTimeout(() => setMsg({ type: "", text: "" }), 4000);
    }
  };

  // Fetch lead investigators for the dropdown
  useEffect(() => {
    api
      .get("/users/leads")
      .then((res) => setLeaders(Array.isArray(res.data) ? res.data : []))
      .catch(() => setLeaders([]));
  }, []);

  // Search users as you type
  const handleSearch = async (e) => {
    const value = e.target.value;
    setSearchTerm(value);
    if (value.length >= 1) {
      try {
        const res = await api.get(`/users/search?q=${encodeURIComponent(value)}`);
        const existingIds = new Set(assignedMembers.map((m) => m._id));
        setSearchResults(
          (Array.isArray(res.data) ? res.data : []).filter(
            (u) => !existingIds.has(u._id)
          )
        );
      } catch {
        setSearchResults([]);
      }
    } else {
      setSearchResults([]);
    }
  };

  const addMember = (member) => {
    if (!assignedMembers.find((m) => m._id === member._id)) {
      setAssignedMembers((prev) => [...prev, member]);
    }
    setSearchTerm("");
    setSearchResults([]);
  };

  const removeMember = (id) => {
    setAssignedMembers((prev) => prev.filter((m) => m._id !== id));
  };

  const handleCreateCase = async () => {
    // Validation
    if (!title.trim()) return flash("error", "Case title is required");
    if (!description.trim()) return flash("error", "Description is required");

    setSubmitting(true);
    try {
      const payload = {
        title: title.trim(),
        description: description.trim(),
        status,
        priority,
        start_date: startDate ? new Date(startDate).toISOString() : new Date().toISOString(),
        leader_id: leader || undefined,
        member_ids: assignedMembers.map((m) => m._id),
      };

      await api.post("/create-case", payload);
      flash("success", "Case created successfully! Redirecting to cases...");
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to create case");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="dashboardMain">
      {/* Header */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText">
            <span>LEGALLENS</span> Create Case
          </h1>
          <p className="systemStatus">Fill in the details to create a new investigation case</p>
        </div>
      </header>

      {/* Alert */}
      {msg.text && (
        <div
          className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
          style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "1.5rem" }}
        >
          {msg.type === "success" ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
          {msg.text}
        </div>
      )}

      <div className="formSectionCard">
        {/* Case Details */}
        <div className="sectionHeader">
          <div className="indicatorDot" />
          <h2>CASE INFORMATION</h2>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "1.25rem", padding: "1.5rem" }}>
          {/* Title */}
          <div className="inputGroup" style={{ gridColumn: "span 2" }}>
            <label>Case Title *</label>
            <input
              type="text"
              placeholder="e.g. Downtown Bank Robbery Investigation"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
            />
          </div>

          {/* Description */}
          <div className="inputGroup" style={{ gridColumn: "span 2" }}>
            <label>Description *</label>
            <textarea
              placeholder="Provide a detailed description of the case..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows={4}
              style={{ resize: "vertical" }}
            />
          </div>

          {/* Priority */}
          <div className="inputGroup">
            <label>Priority</label>
            <select
              value={priority}
              onChange={(e) => setPriority(e.target.value)}
              style={{
                background: "#1e293b",
                border: "1px solid rgba(255,255,255,0.08)",
                color: "#fff",
                padding: "0.75rem 1rem",
                borderRadius: 8,
                fontSize: "0.9rem",
                width: "100%",
              }}
            >
              <option value="High">High</option>
              <option value="Medium">Medium</option>
              <option value="Low">Low</option>
            </select>
          </div>

          {/* Status */}
          <div className="inputGroup">
            <label>Status</label>
            <select
              value={status}
              onChange={(e) => setStatus(e.target.value)}
              style={{
                background: "#1e293b",
                border: "1px solid rgba(255,255,255,0.08)",
                color: "#fff",
                padding: "0.75rem 1rem",
                borderRadius: 8,
                fontSize: "0.9rem",
                width: "100%",
              }}
            >
              <option value="Open">Open</option>
              <option value="Closed">Closed</option>
              <option value="Archived">Archived</option>
            </select>
          </div>

          {/* Start Date */}
          <div className="inputGroup">
            <label>Start Date</label>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              max={new Date().toISOString().split("T")[0]}
            />
          </div>

          {/* Lead Investigator */}
          <div className="inputGroup">
            <label>Lead Investigator</label>
            <select
              value={leader}
              onChange={(e) => setLeader(e.target.value)}
              style={{
                background: "#1e293b",
                border: "1px solid rgba(255,255,255,0.08)",
                color: "#fff",
                padding: "0.75rem 1rem",
                borderRadius: 8,
                fontSize: "0.9rem",
                width: "100%",
              }}
            >
              <option value="">— Select Lead Investigator —</option>
              {leaders.map((l) => (
                <option key={l._id} value={l._id}>
                  {l.name}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* Assign Members */}
        <div style={{ padding: "0 1.5rem 1.5rem" }}>
          <div className="sectionHeader" style={{ marginBottom: "1rem" }}>
            <div className="indicatorDot" style={{ background: "#34d399" }} />
            <h2>ASSIGN TEAM MEMBERS</h2>
          </div>

          {/* Search */}
          <div style={{ position: "relative", maxWidth: 420, marginBottom: "1rem" }}>
            <div className="membersSearch">
              <Search size={16} color="#475569" />
              <input
                type="text"
                placeholder="Search by member name..."
                value={searchTerm}
                onChange={handleSearch}
                style={{
                  background: "transparent",
                  border: "none",
                  outline: "none",
                  color: "#fff",
                  fontSize: "0.875rem",
                  flex: 1,
                }}
              />
              {searchTerm && (
                <button
                  onClick={() => { setSearchTerm(""); setSearchResults([]); }}
                  style={{ background: "none", border: "none", cursor: "pointer", color: "#64748b" }}
                >
                  <X size={14} />
                </button>
              )}
            </div>

            {searchResults.length > 0 && (
              <div className="searchDropdown" style={{ position: "absolute", width: "100%", zIndex: 50 }}>
                {searchResults.map((u) => (
                  <div
                    key={u._id}
                    className="searchItem"
                    style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}
                  >
                    <div>
                      <p style={{ margin: 0, fontWeight: 600, fontSize: "0.875rem" }}>{u.name}</p>
                      <p style={{ margin: 0, color: "#64748b", fontSize: "0.75rem" }}>
                        {u.role_id?.role_name?.replace(/_/g, " ")}
                      </p>
                    </div>
                    <button
                      onClick={() => addMember(u)}
                      style={{
                        background: "rgba(79,70,229,0.2)",
                        border: "1px solid rgba(79,70,229,0.3)",
                        color: "#818cf8",
                        padding: "4px 12px",
                        borderRadius: 6,
                        cursor: "pointer",
                        fontSize: "0.8rem",
                        fontWeight: 600,
                      }}
                    >
                      <Plus size={12} style={{ display: "inline", marginRight: 4 }} />
                      Add
                    </button>
                  </div>
                ))}
              </div>
            )}

            {searchTerm.length >= 1 && searchResults.length === 0 && (
              <p style={{ color: "#475569", fontSize: "0.8rem", marginTop: "0.5rem" }}>
                No users found matching "{searchTerm}"
              </p>
            )}
          </div>

          {/* Assigned members chips */}
          {assignedMembers.length > 0 && (
            <div style={{ display: "flex", flexWrap: "wrap", gap: "0.5rem" }}>
              {assignedMembers.map((m) => (
                <div
                  key={m._id}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "0.5rem",
                    background: "rgba(79,70,229,0.1)",
                    border: "1px solid rgba(79,70,229,0.25)",
                    borderRadius: 20,
                    padding: "4px 12px",
                    fontSize: "0.8rem",
                    color: "#818cf8",
                  }}
                >
                  <div
                    style={{
                      width: 20,
                      height: 20,
                      borderRadius: "50%",
                      background: "rgba(79,70,229,0.3)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontWeight: 700,
                      fontSize: "0.65rem",
                    }}
                  >
                    {m.name?.charAt(0)?.toUpperCase()}
                  </div>
                  {m.name}
                  <button
                    onClick={() => removeMember(m._id)}
                    style={{ background: "none", border: "none", cursor: "pointer", color: "#818cf8", display: "flex", padding: 0 }}
                  >
                    <X size={12} />
                  </button>
                </div>
              ))}
            </div>
          )}

          {assignedMembers.length === 0 && (
            <p style={{ color: "#334155", fontSize: "0.8rem" }}>
              No members assigned yet. Search above to add team members.
            </p>
          )}
        </div>

        {/* Action buttons */}
        <div
          style={{
            padding: "1rem 1.5rem 1.5rem",
            display: "flex",
            gap: "1rem",
            justifyContent: "flex-end",
            borderTop: "1px solid rgba(255,255,255,0.05)",
          }}
        >
          <button
            className="btnCancel"
            onClick={() => navigate("/cases")}
            disabled={submitting}
          >
            Cancel
          </button>
          <button
            className="btnCreate"
            onClick={handleCreateCase}
            disabled={submitting}
          >
            {submitting ? "Creating..." : <><Plus size={16} style={{ marginRight: 6 }} />Create Case</>}
          </button>
        </div>
      </div>
    </div>
  );
}
